from math import gcd
def A036505(n: int) -> int:
    t_num, t_den = 1, 1   # term
    s_num, s_den = 0, 1   # sum
    for k in range(n + 1):
        if k > 0:
            t_num *= (n - k + 1)
            t_den *= (n + 1)
            g = gcd(t_num, t_den)
            t_num //= g
            t_den //= g
        num = s_num * t_den + t_num * s_den
        den = s_den * t_den
        g = gcd(num, den)
        s_num, s_den = num // g, den // g
    return s_den
